@namespace sv_58caf905da6b4f7b9ff184a427b8f9b3.Components.Pages.Catalog

<div class="product-card" @onclick="HandleCardClick">
    <div class="product-image" role="img" aria-label="@Product.Name">
        @Product.Name
    </div>
    <div class="product-info">
        <h3 class="product-name">@Product.Name</h3>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating" aria-label="@($"Rating: {RatingValue} out of 5")">
            @RatingDisplay
        </div>
        @if (!Product.InStock)
        {
            <span class="badge-out-of-stock">Out of Stock</span>
        }
        <button class="btn-add-to-cart"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private int RatingValue => (int)Math.Round(Product.Rating);

    private string RatingDisplay
    {
        get
        {
            var filled = RatingValue;
            var empty = 5 - filled;
            return new string('★', filled) + new string('☆', empty);
        }
    }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        await OnAddToCart.InvokeAsync(Product);
    }
}

@namespace sv_58caf905da6b4f7b9ff184a427b8f9b3.Components.Pages.Catalog

<aside class="catalog-filters">
    <h2>Filters</h2>

    <div class="filter-section">
        <h3>Categories</h3>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <label class="filter-checkbox">
                    <input type="checkbox"
                           checked="@IsSelected(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                    @category
                </label>
            }
        }
    </div>

    <div class="filter-section">
        <h3>Price Range</h3>
        <label>
            Min Price
            <input type="number" min="0" step="0.01"
                   value="@_minPrice"
                   @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
        </label>
        <label>
            Max Price
            <input type="number" min="0" step="0.01"
                   value="@_maxPrice"
                   @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </label>
    </div>

    <div class="filter-section">
        <label class="filter-checkbox">
            <input type="checkbox"
                   checked="@_inStockOnly"
                   @onchange="@(e => _inStockOnly = (bool)e.Value!)" />
            In Stock Only
        </label>
    </div>

    <div class="filter-actions">
        <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
    </div>
</aside>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFiltersApplied { get; set; }

    [Parameter]
    public EventCallback OnFiltersCleared { get; set; }

    private List<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private bool IsSelected(string category) => _selectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
        {
            if (!_selectedCategories.Contains(category))
                _selectedCategories.Add(category);
        }
        else
        {
            _selectedCategories.Remove(category);
        }
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? new List<string>(_selectedCategories) : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFiltersApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFiltersCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@namespace sv_58caf905da6b4f7b9ff184a427b8f9b3.Components.Pages.Catalog

<div class="catalog-toolbar">
    <div class="toolbar-sort">
        <label for="sort-select">Sort by:</label>
        <select id="sort-select" value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <div class="toolbar-info">
        @if (TotalCount > 0)
        {
            <span>Showing @StartItem–@EndItem of @TotalCount products</span>
        }
    </div>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private int StartItem => TotalCount == 0 ? 0 : (Page - 1) * PageSize + 1;
    private int EndItem => Math.Min(Page * PageSize, TotalCount);

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_58caf905da6b4f7b9ff184a427b8f9b3.Components.Pages.Catalog

<nav class="catalog-pagination" aria-label="Product pagination">
    <button class="btn-page"
            disabled="@(CurrentPage <= 1)"
            @onclick="@(() => GoToPage(CurrentPage - 1))">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        var pageNum = i;
        <button class="btn-page @(pageNum == CurrentPage ? "active" : "")"
                @onclick="@(() => GoToPage(pageNum))">
            @pageNum
        </button>
    }

    <button class="btn-page"
            disabled="@(CurrentPage >= TotalPages)"
            @onclick="@(() => GoToPage(CurrentPage + 1))">
        Next
    </button>
</nav>

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

