@page "/catalog"
@namespace sv_58caf905da6b4f7b9ff184a427b8f9b3.Components.Pages.Catalog
@using sv_58caf905da6b4f7b9ff184a427b8f9b3
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-page">
    <CatalogFilters Categories="@_categories"
                    OnFiltersApplied="HandleFiltersApplied"
                    OnFiltersCleared="HandleFiltersCleared" />

    <main class="catalog-main">
        @if (_loading)
        {
            <div class="catalog-status">
                <p>Loading products...</p>
            </div>
        }
        else if (_error is not null)
        {
            <div class="catalog-status catalog-error">
                <p>Error loading products: @_error</p>
                <button class="btn-apply" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (_result is null || _result.Items.Count == 0)
        {
            <div class="catalog-status">
                <p>No products found matching your criteria.</p>
            </div>
        }
        else
        {
