.catalog-page {
    display: flex;
    gap: 1.5rem;
    padding: 1rem;
}

/* Sidebar filters */
.catalog-filters {
    width: 25%;
    min-width: 220px;
    padding: 1rem;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    background: #fafafa;
    align-self: flex-start;
}

.catalog-filters h2 {
    margin: 0 0 1rem;
    font-size: 1.25rem;
}

.catalog-filters h3 {
    margin: 0.75rem 0 0.5rem;
    font-size: 0.95rem;
    font-weight: 600;
}

.filter-section {
    margin-bottom: 1rem;
    padding-bottom: 1rem;
    border-bottom: 1px solid #e0e0e0;
}

.filter-section:last-of-type {
    border-bottom: none;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.4rem;
    cursor: pointer;
}

.filter-section label:not(.filter-checkbox) {
    display: block;
    margin-bottom: 0.5rem;
    font-size: 0.875rem;
}

.filter-section input[type="number"] {
    width: 100%;
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    margin-top: 0.25rem;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 1rem;
}

.btn-apply {
    padding: 0.5rem 1rem;
    background: #0d6efd;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-weight: 500;
}

.btn-apply:hover {
    background: #0b5ed7;
}

.btn-clear {
    padding: 0.5rem 1rem;
    background: transparent;
    color: #555;
    border: 1px solid #ccc;
    border-radius: 4px;
